class DeepLinkParser {
  /**
   * Parse a deep link URL into its components.
   * Returns null if the URL is malformed or uses a disallowed scheme.
   */
  static parseUrl(url) {
    if (!url || typeof url !== 'string') {
      DeepLinkLogger.warn('Received null or non-string URL');
      return null;
    }

    // Limit URL length to prevent abuse
    if (url.length > 2048) {
      DeepLinkLogger.security('URL exceeds maximum length', {
        length: url.length,
      });
      return null;
    }

    // Decode and check for encoded attacks
    let decodedUrl;
    try {
      decodedUrl = decodeURIComponent(url);
    } catch (e) {
      DeepLinkLogger.security('Failed to decode URL', { url: url.substring(0, 100) });
      return null;
    }

    // Check for null bytes or other injection characters
    if (decodedUrl.includes('\0') || decodedUrl.includes('\n') || decodedUrl.includes('\r')) {
      DeepLinkLogger.security('URL contains forbidden characters', {
        url: url.substring(0, 100),
      });
      return null;
    }

    try {
      // Extract scheme
      const schemeMatch = url.match(/^([a-zA-Z][a-zA-Z0-9+\-.]*):\/\//);
      if (!schemeMatch) {
        DeepLinkLogger.warn('No valid scheme found in URL', {
          url: url.substring(0, 100),
        });
        return null;
      }

      const scheme = schemeMatch[1].toLowerCase();

      // Validate scheme against allowlist
      if (scheme !== ALLOWED_SCHEME) {
        DeepLinkLogger.security('Disallowed scheme', { scheme });
        return null;
      }

      // Extract the rest after scheme://
      const rest = url.substring(schemeMatch[0].length);

      // Split path and query
      const [pathPart, queryString] = rest.split('?');

      // Normalize path: remove trailing slash, collapse multiple slashes
      const normalizedPath = pathPart
        .replace(/\/+/g, '/')
        .replace(/\/$/, '')
        .replace(/^\//, '');

      // Reject path traversal attempts
      if (normalizedPath.includes('..') || normalizedPath.includes('./')) {
        DeepLinkLogger.security('Path traversal attempt detected', {
          path: normalizedPath,
        });
        return null;
      }

      const pathSegments = normalizedPath.split('/').filter(Boolean);

      // Parse query parameters
      const queryParams = {};
      if (queryString) {
        const params = queryString.split('&');
        for (const param of params) {
          const [key, value] = param.split('=');
          if (key && value !== undefined) {
            const decodedKey = decodeURIComponent(key);
            const decodedValue = decodeURIComponent(value);
            queryParams[decodedKey] = decodedValue;
          }
        }
      }

      return {
        scheme,
        path: normalizedPath,
        pathSegments,
        queryParams,
        originalUrl: url,
      };
    } catch (error) {
      DeepLinkLogger.error('Error parsing URL', {
        error: error.message,
        url: url.substring(0, 100),
      });
      return null;
    }
  }
}

