class RouteMatcher {
  /**
   * Match a parsed URL path against the allowlisted routes.
   * Returns the matched route config and extracted path parameters, or null.
   */
  static matchRoute(pathSegments) {
    for (const [pattern, config] of Object.entries(ALLOWED_ROUTES)) {
      const patternSegments = pattern.split('/');

      if (patternSegments.length !== pathSegments.length) {
        continue;
      }

      const extractedParams = {};
      let isMatch = true;

      for (let i = 0; i < patternSegments.length; i++) {
        const patternSeg = patternSegments[i];
        const pathSeg = pathSegments[i];

        if (patternSeg.startsWith(':')) {
          // Dynamic parameter
          const paramName = patternSeg.substring(1);
          extractedParams[paramName] = pathSeg;
        } else if (patternSeg !== pathSeg) {
          isMatch = false;
          break;
        }
      }

      if (isMatch) {
        return {
          routePattern: pattern,
          config,
          extractedParams,
        };
      }
    }

    return null;
  }
}

// ============================================================
// PARAMETER VALIDATOR
// ============================================================

class ParamValidator {
  /**
   * Validate and sanitize extracted path parameters against the route config.
   * Returns sanitized params or null if validation fails.
   */
  static validatePathParams(extractedParams, routeConfig) {
    const sanitizedParams = {};
    const paramRules = routeConfig.params || {};

    // Check for required params
    for (const [paramName, rules] of Object.entries(paramRules)) {
      if (rules.required && !(paramName in extractedParams)) {
        DeepLinkLogger.warn('Missing required parameter', { paramName });
        return null;
      }
    }

    // Validate each extracted param
    for (const [paramName, value] of Object.entries(extractedParams)) {
      const rules = paramRules[paramName];

      if (!rules) {
        // Parameter not in allowlist for this route - reject
        DeepLinkLogger.security('Unexpected parameter in path', { paramName });
        return null;
      }

      // Sanitize
      let sanitizedValue = rules.sanitize ? rules.sanitize(value) : value;

      // Validate against pattern
      if (rules.pattern && !rules.pattern.test(sanitizedValue)) {
        DeepLinkLogger.security('Parameter failed validation', {
          paramName,
          value: sanitizedValue.substring(0, 50),
        });
        return null;
      }

      sanitizedParams[paramName] = sanitizedValue;
    }

    return sanitizedParams;
  }

  /**
   * Validate and sanitize query parameters against the global allowlist.
   * Unknown query params are silently dropped.
   */
  static validateQueryParams(queryParams) {
    const sanitizedQuery = {};

    for (const [key, value] of Object.entries(queryParams)) {
      const rules = ALLOWED_QUERY_PARAMS[key];

      if (!rules) {
        // Unknown query param - drop it silently
        DeepLinkLogger.info('Dropping unknown query parameter', { key });
        continue;
      }

      let sanitizedValue = rules.sanitize ? rules.sanitize(value) : value;

      if (rules.pattern && !rules.pattern.test(sanitizedValue)) {
        DeepLinkLogger.warn('Query parameter failed validation', {
          key,
          value: sanitizedValue.substring(0, 50),
        });
        continue; // Drop invalid query params
      }

      sanitizedQuery[key] = sanitizedValue;
    }

    return sanitizedQuery;
  }
}

