// AUTHORIZATION CHECKER
// ============================================================

class AuthorizationChecker {
  /**
   * Check if the current user is authorized to access the matched route.
   * Returns { authorized: boolean, reason?: string }
   */
  static checkAuthorization(routeConfig) {
    // If route doesn't require auth, allow
    if (!routeConfig.requiresAuth) {
      return { authorized: true };
    }

    // Check authentication
    if (!AuthService.isAuthenticated()) {
      DeepLinkLogger.security('Unauthenticated access attempt to protected route', {
        screen: routeConfig.screen,
      });
      return {
        authorized: false,
        reason: 'authentication_required',
        redirectTo: 'Login',
      };
    }

    // Check role-based authorization
    if (routeConfig.requiredRoles && routeConfig.requiredRoles.length > 0) {
      if (!AuthService.hasAnyRole(routeConfig.requiredRoles)) {
        DeepLinkLogger.security('Unauthorized role access attempt', {
          screen: routeConfig.screen,
          requiredRoles: routeConfig.requiredRoles,
          userRoles: AuthService.getCurrentUser()?.roles,
        });
        return {
          authorized: false,
          reason: 'insufficient_permissions',
        };
      }
    }

    return { authorized: true };
  }
}

