// MAIN DEEP LINK HANDLER
// ============================================================

class DeepLinkHandler {
  constructor(navigationRef) {
    this.navigationRef = navigationRef;
    this.rateLimiter = new RateLimiter(RATE_LIMIT.maxRequests, RATE_LIMIT.windowMs);
    this.pendingDeepLink = null;
  }

  /**
   * Process a deep link URL end-to-end:
   * 1. Rate limit check
   * 2. Parse URL
   * 3. Match against allowlisted routes
   * 4. Validate parameters
   * 5. Check authorization
   * 6. Navigate
   */
  async handleDeepLink(url) {
    DeepLinkLogger.info('Processing deep link', { url: url?.substring(0, 200) });

    // Step 1: Rate limiting
    if (!this.rateLimiter.isAllowed()) {
      Alert.alert(
        'Too Many Requests',
        'Please wait a moment before trying again.'
      );
      return { success: false, reason: 'rate_limited' };
    }

    // Step 2: Parse URL
    const parsed = DeepLinkParser.parseUrl(url);
    if (!parsed) {
      DeepLinkLogger.warn('Failed to parse deep link URL', {
        url: url?.substring(0, 200),
      });
      return { success: false, reason: 'invalid_url' };
    }

    // Step 3: Match route against allowlist
    const match = RouteMatcher.matchRoute(parsed.pathSegments);
    if (!match) {
      DeepLinkLogger.security('No matching allowlisted route', {
        path: parsed.path,
      });
      return { success: false, reason: 'route_not_found' };
    }

    DeepLinkLogger.info('Route matched', {
      pattern: match.routePattern,
      screen: match.config.screen,
    });

    // Step 4: Validate path parameters
    const validatedPathParams = ParamValidator.validatePathParams(
      match.extractedParams,
      match.config
    );
    if (validatedPathParams === null) {
      DeepLinkLogger.security('Path parameter validation failed', {
        pattern: match.routePattern,
      });
      return { success: false, reason: 'invalid_parameters' };
    }

    // Step 4b: Validate query parameters
    const validatedQueryParams = ParamValidator.validateQueryParams(
      parsed.queryParams
    );

    // Step 5: Authorization check
    const authResult = AuthorizationChecker.checkAuthorization(match.config);
    if (!authResult.authorized) {
      if (authResult.reason === 'authentication_required') {
        // Store pending deep link and redirect to login
        this.pendingDeepLink = {
          screen: match.config.screen,
          params: { ...validatedPathParams, ...validatedQueryParams },
        };

        DeepLinkLogger.info('Redirecting to login, deep link pending', {
          screen: match.config.screen,
        });

        this.navigate('Login', {
          returnTo: match.config.screen,
        });

        return { success: false, reason: 'authentication_required', pending: true };
      }

      if (authResult.reason === 'insufficient_permissions') {
        Alert.alert(
          'Access Denied',
          'You do not have permission to access this page.'
        );
        return { success: false, reason: 'insufficient_permissions' };
      }

      return { success: false, reason: authResult.reason };
    }

    // Step 6: Navigate
    const navigationParams = {
      ...validatedPathParams,
      ...validatedQueryParams,
      _deepLink: true, // Flag so screens know they were opened via deep link
    };

    DeepLinkLogger.info('Navigating via deep link', {
      screen: match.config.screen,
      params: navigationParams,
    });

    this.navigate(match.config.screen, navigationParams);

    return {
      success: true,
      screen: match.config.screen,
      params: navigationParams,
    };
  }

  /**
   * Navigate using the navigation ref.
   */
  navigate(screen, params) {
    if (this.navigationRef?.current?.isReady()) {
      this.navigationRef.current.navigate(screen, params);
    } else {
      DeepLinkLogger.warn('Navigation not ready, queuing deep link', { screen });
      this.pendingDeepLink = { screen, params };
    }
  }

  /**
   * Process any pending deep link (e.g., after login or navigation ready).
   */
  processPendingDeepLink() {
    if (this.pendingDeepLink) {
      const { screen, params } = this.pendingDeepLink;
      this.pendingDeepLink = null;

      DeepLinkLogger.info('Processing pending deep link', { screen });
      this.navigate(screen, params);
      return true;
    }
    return false;
  }

  /**
   * Clear any pending deep link.
   */
  clearPendingDeepLink() {
    this.pendingDeepLink = null;
  }
}

