// REACT HOOK: useDeepLinkHandler
// ============================================================

/**
 * React hook that sets up deep link listening using the Linking API.
 * Should be used in your root App component or navigation container.
 *
 * @param {object} navigationRef - React Navigation ref
 */
function useDeepLinkHandler(navigationRef) {
  const handlerRef = useRef(null);
  const navigation = useNavigation();

  // Initialize handler
  if (!handlerRef.current) {
    handlerRef.current = new DeepLinkHandler(navigationRef);
  }

  const handleUrl = useCallback(
    async (event) => {
      const url = typeof event === 'string' ? event : event?.url;
      if (url) {
        await handlerRef.current.handleDeepLink(url);
      }
    },
    []
  );

  useEffect(() => {
    // Handle deep link that opened the app (cold start)
    const handleInitialUrl = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          DeepLinkLogger.info('App opened via deep link (cold start)', {
            url: initialUrl.substring(0, 200),
          });
          await handleUrl(initialUrl);
        }
      } catch (error) {
        DeepLinkLogger.error('Error getting initial URL', {
          error: error.message,
        });
      }
    };

    handleInitialUrl();

    // Handle deep links while app is running (warm start)
    const subscription = Linking.addEventListener('url', handleUrl);

    return () => {
      subscription?.remove();
    };
  }, [handleUrl]);

  return {
    handler: handlerRef.current,
    processPendingDeepLink: () => handlerRef.current.processPendingDeepLink(),
    clearPendingDeepLink: () => handlerRef.current.clearPendingDeepLink(),
  };
}

